# Auto-generated by dev iter-2 (test-writer dispatch) — extended M-coverage
# AC ID: AC-07  ac_uid: m1_negatives_unchanged  type: data
# Covers M1 deeper aspect: every original negative event delta must remain
# byte-identical post-rebalance (user explicitly said "min stays -40, negatives unchanged").

import re
from pathlib import Path

AC_UID = "m1_negatives_unchanged"
AC_TYPE = "data"

SCRIPT = Path(__file__).resolve().parents[3] / "scripts" / "score-update.sh"

EXPECTED_NEGATIVE_EVENTS = {
    "close_fail_qa_pass": {"dev": -10, "ba": -5, "qa": -12},
    "close_fail_qa_fail": {"dev": -10, "ba": -5, "qa": 0},
    "qa_reject_pre_pass": {"dev": -5, "ba": -3, "qa": 0},
    "qa_reject_first_fix": {"dev": 0, "ba": 0, "qa": -3},
    "qa_reject_second_fix": {"dev": 0, "ba": 0, "qa": -8},
    "qa_reject_third_fix": {"dev": 0, "ba": 0, "qa": -40},
}


def _parse_event_deltas():
    text = SCRIPT.read_text()
    m = re.search(r"EVENT_DELTAS\s*=\s*\{(.*?)^\}", text, re.DOTALL | re.MULTILINE)
    assert m
    block = m.group(1)
    entries = re.findall(
        r"""["']([^"']+)["']\s*:\s*\{\s*["']dev["']\s*:\s*(-?\d+)\s*,\s*["']ba["']\s*:\s*(-?\d+)\s*,\s*["']qa["']\s*:\s*(-?\d+)\s*\}""",
        block,
    )
    return {n: {"dev": int(d), "ba": int(b), "qa": int(q)} for n, d, b, q in entries}


def test_AC_07_M1_negatives_unchanged():
    """
    GIVEN: M1 rebalance touched only positive EVENT_DELTAS values
    WHEN:  the dict is parsed
    THEN:  every negative event listed by the user-verbatim "min stays -40" requirement
           has byte-identical pre-change values; min(negative) == -40.
    """
    deltas = _parse_event_deltas()
    for event, expected in EXPECTED_NEGATIVE_EVENTS.items():
        # Some events may not exist in current schema — that's OK; only fail if present and wrong.
        if event not in deltas:
            continue
        assert deltas[event] == expected, (
            f"negative event {event!r} was modified: expected {expected} got {deltas[event]}"
        )
    # Hard floor must remain -40
    all_values = [v for ev in deltas.values() for v in ev.values()]
    assert min(all_values) == -40, f"min negative must be -40, got {min(all_values)}"
